// lib/services/aws_s3_service.dart
import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';
import 'package:http/http.dart' as http;
import 'package:intl/intl.dart';
import 'package:path/path.dart' as p;
import '../config/env_config.dart';

class AwsS3Service {
  final String _accessKey;
  final String _secretKey;
  final String _region;
  final String _bucket;

  AwsS3Service()
      : _accessKey = EnvConfig.awsAccessKeyId,
        _secretKey = EnvConfig.awsSecretAccessKey,
        _region = EnvConfig.awsRegion,
        _bucket = EnvConfig.awsS3Bucket;

  String get _host => '$_bucket.s3.$_region.amazonaws.com';
  String get _baseUrl => 'https://$_host';

  Future<S3UploadResult> uploadFile(File file) async {
    final timestamp = DateTime.now().toUtc();
    final dateStamp = DateFormat('yyyyMMdd').format(timestamp);
    final amzDate = DateFormat("yyyyMMdd'T'HHmmss'Z'").format(timestamp);

    final fileName = '${DateTime.now().millisecondsSinceEpoch}_${p.basename(file.path)}';
    final objectKey = 'uploads/$fileName';

    final fileBytes = await file.readAsBytes();
    final contentType = _getContentType(file.path);
    final payloadHash = sha256.convert(fileBytes).toString();

    final headers = <String, String>{
      'Host': _host,
      'Content-Type': contentType,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
    };

    final signedHeaders = (headers.keys.toList()..sort())
        .map((k) => k.toLowerCase())
        .join(';');

    final canonicalHeaders = (headers.keys.toList()..sort())
        .map((k) => '${k.toLowerCase()}:${headers[k]!.trim()}')
        .join('\n');

    final canonicalRequest = [
      'PUT',
      '/$objectKey',
      '',
      '$canonicalHeaders\n',
      signedHeaders,
      payloadHash,
    ].join('\n');

    final credentialScope = '$dateStamp/$_region/s3/aws4_request';
    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(dateStamp);
    final signature = Hmac(sha256, signingKey)
        .convert(utf8.encode(stringToSign))
        .toString();

    final authorization =
        'AWS4-HMAC-SHA256 Credential=$_accessKey/$credentialScope, '
        'SignedHeaders=$signedHeaders, Signature=$signature';

    headers['Authorization'] = authorization;

    final uri = Uri.parse('$_baseUrl/$objectKey');

    final response = await http.put(
      uri,
      headers: headers,
      body: fileBytes,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      return S3UploadResult(
        success: true,
        url: uri.toString(),
        objectKey: objectKey,
      );
    } else {
      return S3UploadResult(
        success: false,
        error: 'Upload failed: ${response.statusCode} - ${response.body}',
      );
    }
  }

  List<int> _getSignatureKey(String dateStamp) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$_secretKey'))
        .convert(utf8.encode(dateStamp))
        .bytes;
    final kRegion =
        Hmac(sha256, kDate).convert(utf8.encode(_region)).bytes;
    final kService =
        Hmac(sha256, kRegion).convert(utf8.encode('s3')).bytes;
    final kSigning =
        Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
    return kSigning;
  }

  String _getContentType(String filePath) {
    final ext = p.extension(filePath).toLowerCase();
    switch (ext) {
      case '.jpg':
      case '.jpeg':
        return 'image/jpeg';
      case '.png':
        return 'image/png';
      case '.gif':
        return 'image/gif';
      case '.webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }
}

class S3UploadResult {
  final bool success;
  final String? url;
  final String? objectKey;
  final String? error;

  S3UploadResult({
    required this.success,
    this.url,
    this.objectKey,
    this.error,
  });
}


// lib/services/google_vision_service.dart
import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;
import '../config/env_config.dart';

class GoogleVisionService {
  final String _apiKey;

  static const String _baseUrl =
      'https://vision.googleapis.com/v1/images:annotate';

  GoogleVisionService() : _apiKey = EnvConfig.googleCloudApiKey;

  Future<VisionAnalysisResult> analyzeImage(File imageFile) async {
    final bytes = await imageFile.readAsBytes();
    final base64Image = base64Encode(bytes);

    final requestBody = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'FACE_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION'},
            {'type': 'IMAGE_PROPERTIES'},
            {'type': 'LANDMARK_DETECTION', 'maxResults': 5},
          ],
        }
      ]
    };

    final response = await http.post(
      Uri.parse('$_baseUrl?key=$_apiKey'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(requestBody),
    );

    if (response.statusCode == 200) {
      final json = jsonDecode(response.body);
      return _parseResponse(json);
    } else {
      return VisionAnalysisResult(
        success: false,
        error: 'Vision API error: ${response.statusCode} - ${response.body}',
      );
    }
  }

  VisionAnalysisResult _parseResponse(Map<String, dynamic> json) {
    try {
      final responses = json['responses'] as List;
      if (responses.isEmpty) {
        return VisionAnalysisResult(success: false, error: 'Empty response');
      }

      final result = responses[0] as Map<String, dynamic>;

      final labels = <VisionLabel>[];
      if (result.containsKey('labelAnnotations')) {
        for (final label in result['labelAnnotations']) {
          labels.add(VisionLabel(
            description: label['description'] ?? '',
            score: (label['score'] ?? 0.0).toDouble(),
          ));
        }
      }

      final faces = <FaceAnnotation>[];
      if (result.containsKey('faceAnnotations')) {
        for (final face in result['faceAnnotations']) {
          faces.add(FaceAnnotation(
            joyLikelihood: face['joyLikelihood'] ?? 'UNKNOWN',
            sorrowLikelihood: face['sorrowLikelihood'] ?? 'UNKNOWN',
            angerLikelihood: face['angerLikelihood'] ?? 'UNKNOWN',
            surpriseLikelihood: face['surpriseLikelihood'] ?? 'UNKNOWN',
            detectionConfidence:
                (face['detectionConfidence'] ?? 0.0).toDouble(),
          ));
        }
      }

      final texts = <String>[];
      if (result.containsKey('textAnnotations')) {
        for (final text in result['textAnnotations']) {
          texts.add(text['description'] ?? '');
        }
      }

      final objects = <DetectedObject>[];
      if (result.containsKey('localizedObjectAnnotations')) {
        for (final obj in result['localizedObjectAnnotations']) {
          objects.add(DetectedObject(
            name: obj['name'] ?? '',
            score: (obj['score'] ?? 0.0).toDouble(),
          ));
        }
      }

      SafeSearchAnnotation? safeSearch;
      if (result.containsKey('safeSearchAnnotation')) {
        final ss = result['safeSearchAnnotation'];
        safeSearch = SafeSearchAnnotation(
          adult: ss['adult'] ?? 'UNKNOWN',
          violence: ss['violence'] ?? 'UNKNOWN',
          racy: ss['racy'] ?? 'UNKNOWN',
        );
      }

      final landmarks = <String>[];
      if (result.containsKey('landmarkAnnotations')) {
        for (final lm in result['landmarkAnnotations']) {
          landmarks.add(lm['description'] ?? '');
        }
      }

      final dominantColors = <DominantColor>[];
      if (result.containsKey('imagePropertiesAnnotation')) {
        final props = result['imagePropertiesAnnotation'];
        if (props.containsKey('dominantColors')) {
          final colors = props['dominantColors']['colors'] as List? ?? [];
          for (final color in colors.take(5)) {
            final c = color['color'] ?? {};
            dominantColors.add(DominantColor(
              red: (c['red'] ?? 0).toInt(),
              green: (c['green'] ?? 0).toInt(),
              blue: (c['blue'] ?? 0).toInt(),
              score: (color['score'] ?? 0.0).toDouble(),
              pixelFraction: (color['pixelFraction'] ?? 0.0).toDouble(),
            ));
          }
        }
      }

      return VisionAnalysisResult(
        success: true,
        labels: labels,
        faces: faces,
        texts: texts,
        objects: objects,
        safeSearch: safeSearch,
        landmarks: landmarks,
        dominantColors: dominantColors,
      );
    } catch (e) {
      return VisionAnalysisResult(
        success: false,
        error: 'Parse error: $e',
      );
    }
  }
}

class VisionAnalysisResult {
  final bool success;
  final String? error;
  final List<VisionLabel> labels;
  final List<FaceAnnotation> faces;
  final List<String> texts;
  final List<DetectedObject> objects;
  final SafeSearchAnnotation? safeSearch;
  final List<String> landmarks;
  final List<DominantColor> dominantColors;

  VisionAnalysisResult({
    required this.success,
    this.error,
    this.labels = const [],
    this.faces = const [],
    this.texts = const [],
    this.objects = const [],
    this.safeSearch,
    this.landmarks = const [],
    this.dominantColors = const [],
  });
}

class VisionLabel {
  final String description;
  final double score;
  VisionLabel({required this.description, required this.score});
}

class FaceAnnotation {
  final String joyLikelihood;
  final String sorrowLikelihood;
  final String angerLikelihood;
  final String surpriseLikelihood;
  final double detectionConfidence;

  FaceAnnotation({
    required this.joyLikelihood,
    required this.sorrowLikelihood,
    required this.angerLikelihood,
    required this.surpriseLikelihood,
    required this.detectionConfidence,
  });
}

class DetectedObject {
  final String name;
  final double score;
  DetectedObject({required this.name, required this.score});
}

class SafeSearchAnnotation {
  final String adult;
  final String violence;
  final String racy;
  SafeSearchAnnotation({
    required this.adult,
    required this.violence,
    required this.racy,
  });
}

class DominantColor {
  final int red;
  final int green;
  final int blue;
  final double score;
  final double pixelFraction;
  DominantColor({
    required this.red,
    required this.green,
    required this.blue,
    required this.score,
    required this.pixelFraction,
  });
}


