import 'dart:io';
import 'package:flutter/material.dart';
import 'package:flutter_dotenv/flutter_dotenv.dart';
import 'package:image_picker/image_picker.dart';
import 'config/env_config.dart';
import 'services/aws_s3_service.dart';
import 'services/google_vision_service.dart';

Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();
  await dotenv.load(fileName: '.env');
  runApp(const PhotoAnalyzerApp());
}

class PhotoAnalyzerApp extends StatelessWidget {
  const PhotoAnalyzerApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Photo Analyzer',
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        colorSchemeSeed: Colors.deepPurple,
        useMaterial3: true,
        brightness: Brightness.dark,
      ),
      home: const HomeScreen(),
    );
  }
}

class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  final ImagePicker _picker = ImagePicker();
  final AwsS3Service _s3Service = AwsS3Service();
  final GoogleVisionService _visionService = GoogleVisionService();

  File? _selectedImage;
  bool _isUploading = false;
  bool _isAnalyzing = false;
  S3UploadResult? _uploadResult;
  VisionAnalysisResult? _analysisResult;
  String? _errorMessage;

  @override
  void initState() {
    super.initState();
    _checkConfig();
  }

  void _checkConfig() {
    if (!EnvConfig.isConfigured) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _showConfigError();
      });
    }
  }

  void _showConfigError() {
    showDialog(
      context: context,
      barrierDismissible: false,
      builder: (ctx) => AlertDialog(
        title: const Text('Configuration Missing'),
        content: const Text(
          'Create a .env file in the project root with:\n\n'
          'AWS_ACCESS_KEY_ID=your_key\n'
          'AWS_SECRET_ACCESS_KEY=your_secret\n'
          'AWS_REGION=us-east-1\n'
          'AWS_S3_BUCKET=your_bucket\n'
          'GOOGLE_CLOUD_API_KEY=your_key\n\n'
          'Then restart the app.',
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text('OK'),
          ),
        ],
      ),
    );
  }

  Future<void> _pickImage(ImageSource source) async {
    try {
      final XFile? pickedFile = await _picker.pickImage(
        source: source,
        maxWidth: 2048,
        maxHeight: 2048,
        imageQuality: 85,
      );

      if (pickedFile != null) {
        setState(() {
          _selectedImage = File(pickedFile.path);
          _uploadResult = null;
          _analysisResult = null;
          _errorMessage = null;
        });
      }
    } catch (e) {
      setState(() {
        _errorMessage = 'Failed to pick image: $e';
      });
    }
  }

  Future<void> _uploadAndAnalyze() async {
    if (_selectedImage == null) return;

    setState(() {
      _isUploading = true;
      _isAnalyzing = false;
      _errorMessage = null;
      _uploadResult = null;
      _analysisResult = null;
    });

    // Upload to S3
    try {
      final uploadResult = await _s3Service.uploadFile(_selectedImage!);
      setState(() {
        _uploadResult = uploadResult;
        _isUploading = false;
      });

      if (!uploadResult.success) {
        setState(() {
          _errorMessage = uploadResult.error;
        });
        return;
      }
    } catch (e) {
      setState(() {
        _isUploading = false;
        _errorMessage = 'Upload error: $e';
      });
      return;
    }

    // Analyze with Vision API
    setState(() {
      _isAnalyzing = true;
    });

    try {
      final analysisResult =
          await _visionService.analyzeImage(_selectedImage!);
      setState(() {
        _analysisResult = analysisResult;
        _isAnalyzing = false;
      });

      if (!analysisResult.success) {
        setState(() {
          _errorMessage = analysisResult.error;
        });
      }
    } catch (e) {
      setState(() {
        _isAnalyzing = false;
        _errorMessage = 'Analysis error: $e';
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('📸 Photo Analyzer'),
        centerTitle: true,
        elevation: 2,
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // Image Preview Card
            Card(
              clipBehavior: Clip.antiAlias,
              child: _selectedImage != null
                  ? Image.file(
                      _selectedImage!,
                      height: 300,
                      fit: BoxFit.cover,
                    )
                  : Container(
                      height: 300,
                      color: Colors.grey[800],
                      child: const Column(
                        mainAxisAlignment: MainAxisAlignment.center,
                        children: [
                          Icon(Icons.add_photo_alternate,
                              size: 80, color: Colors.grey),
                          SizedBox(height: 16),
                          Text('Select a photo to analyze',
                              style: TextStyle(color: Colors.grey)),
                        ],
                      ),
                    ),
            ),
            const SizedBox(height: 16),

            // Action Buttons
            Row(
              children: [
                Expanded(
                  child: ElevatedButton.icon(
                    onPressed: _isUploading || _isAnalyzing
                        ? null
                        : () => _pickImage(ImageSource.camera),
                    icon: const Icon(Icons.camera_alt),
                    label: const Text('Camera'),
                  ),
                ),
                const SizedBox(width: 12),
                Expanded(
                  child: ElevatedButton.icon(
                    onPressed: _isUploading || _isAnalyzing
                        ? null
                        : () => _pickImage(ImageSource.gallery),
                    icon: const Icon(Icons.photo_library),
                    label: const Text('Gallery'),
                  ),
                ),
              ],
            ),
            const SizedBox(height: 12),

            // Upload & Analyze Button
            FilledButton.icon(
              onPressed: _selectedImage != null &&
                      !_isUploading &&
                      !_isAnalyzing
                  ? _uploadAndAnalyze
                  : null,
              icon: _isUploading || _isAnalyzing
                  ? const SizedBox(
                      width: 20,
                      height: 20,
                      child: CircularProgressIndicator(
                          strokeWidth: 2, color: Colors.white),
                    )
                  : const Icon(Icons.cloud_upload),
              label: Text(
                _isUploading
                    ? 'Uploading to S3...'
                    : _isAnalyzing
                        ? 'Analyzing with Vision AI...'
                        : 'Upload & Analyze',
              ),
              style: FilledButton.styleFrom(
                padding: const EdgeInsets.symmetric(vertical: 16),
              ),
            ),
            const SizedBox(height: 16),

            // Status Indicators
            if (_uploadResult != null && _uploadResult!.success)
              _buildStatusChip(
                  Icons.cloud_done, 'Uploaded to S3', Colors.green),
            if (_analysisResult != null && _analysisResult!.success)
              _buildStatusChip(
                  Icons.analytics, 'Analysis Complete', Colors.blue),

            // Error Message
            if (_errorMessage != null)
              Card(
                color: Colors.red[900],
                child: Padding(
                  padding: const EdgeInsets.all(12),
                  child: Row(
                    children: [
                      const Icon(Icons.error, color: Colors.red),
                      const SizedBox(width: 8),
                      Expanded(
                        child: Text(
                          _errorMessage!,
                          style: const TextStyle(color: Colors.white),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            const SizedBox(height: 16),

            // Analysis Results
            if (_analysisResult != null && _analysisResult!.success) ...[
              // Labels
              if (_analysisResult!.labels.isNotEmpty)
                _buildResultSection(
                  'Labels',
                  Icons.label,
                  _analysisResult!.labels
                      .map((l) =>
                          '${l.description} (${(l.score * 100).toStringAsFixed(1)}%)')
                      .toList(),
                ),

              // Objects
              if (_analysisResult!.objects.isNotEmpty)
                _buildResultSection(
                  'Objects Detected',
                  Icons.category,
                  _analysisResult!.objects
                      .map((o) =>
                          '${o.name} (${(o.score * 100).toStringAsFixed(1)}%)')
                      .toList(),
                ),

              // Faces
              if (_analysisResult!.faces.isNotEmpty)
                _buildFaceSection(_analysisResult!.faces),

              // Text
              if (_analysisResult!.texts.isNotEmpty)
                _buildResultSection(
                  'Text Detected',
                  Icons.text_fields,
                  [_analysisResult!.texts.first],
                ),

              // Landmarks
              if (_analysisResult!.landmarks.isNotEmpty)
                _buildResultSection(
                  'Landmarks',
                  Icons.place,
                  _analysisResult!.landmarks,
                ),

              // Dominant Colors
              if (_analysisResult!.dominantColors.isNotEmpty)
                _buildColorSection(_analysisResult!.dominantColors),

              // Safe Search
              if (_analysisResult!.safeSearch != null)
                _buildSafeSearchSection(_analysisResult!.safeSearch!),
            ],
          ],
        ),
      ),
    );
  }

  Widget _buildStatusChip(IconData icon, String label, Color color) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 8),
      child: Chip(
        avatar: Icon(icon, color: color, size: 18),
        label: Text(label),
        backgroundColor: color.withOpacity(0.2),
      ),
    );
  }

  Widget _buildResultSection(
      String title, IconData icon, List<String> items) {
    return Card(
      margin: const EdgeInsets.only(bottom: 12),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Icon(icon, size: 20),
                const SizedBox(width: 8),
                Text(title,
                    style: const TextStyle(
                        fontSize: 18, fontWeight: FontWeight.bold)),
              ],
            ),
            const Divider(),
            ...items.map((item) => Padding(
                  padding: const EdgeInsets.symmetric(vertical: 4),
                  child: Text(item, style: const TextStyle(fontSize: 14)),
                )),
          ],
        ),
      ),
    );
  }

  Widget _buildFaceSection(List<FaceAnnotation> faces) {
    return Card(
      margin: const EdgeInsets.only(bottom: 12),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.face, size: 20),
                SizedBox(width: 8),
                Text('Faces Detected',
                    style:
                        TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
              ],
            ),
            const Divider(),
            ...faces.asMap().entries.map((entry) {
              final i = entry.key;
              final face = entry.value;
              return Padding(
                padding: const EdgeInsets.symmetric(vertical: 4),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('Face ${i + 1} (${(face.detectionConfidence * 100).toStringAsFixed(1)}% confidence)',
                        style: const TextStyle(fontWeight: FontWeight.w600)),
                    Text(
                        '  😊 Joy: ${face.joyLikelihood}  😢 Sorrow: ${face.sorrowLikelihood}'),
                    Text(
                        '  😠 Anger: ${face.angerLikelihood}  😲 Surprise: ${face.surpriseLikelihood}'),
                  ],
                ),
              );
            }),
          ],
        ),
      ),
    );
  }

  Widget _buildColorSection(List<DominantColor> colors) {
    return Card(
      margin: const EdgeInsets.only(bottom: 12),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.palette, size: 20),
                SizedBox(width: 8),
                Text('Dominant Colors',
                    style:
                        TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
              ],
            ),
            const Divider(),
            Wrap(
              spacing: 8,
              runSpacing: 8,
              children: colors.map((color) {
                return Chip(
                  avatar: CircleAvatar(
                    backgroundColor:
                        Color.fromRGBO(color.red, color.green, color.blue, 1),
                  ),
                  label: Text(
                    'RGB(${color.red}, ${color.green}, ${color.blue}) '
                    '${(color.pixelFraction * 100).toStringAsFixed(1)}%',
                    style: const TextStyle(fontSize: 12),
                  ),
                );
              }).toList(),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildSafeSearchSection(SafeSearchAnnotation safeSearch) {
    return Card(
      margin: const EdgeInsets.only(bottom: 12),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(
              children: [
                Icon(Icons.shield, size: 20),
                SizedBox(width: 8),
                Text('Safe Search',
                    style:
                        TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
              ],
            ),
            const Divider(),
            Text('Adult: ${safeSearch.adult}'),
            Text('Violence: ${safeSearch.violence}'),
            Text('Racy: ${safeSearch.racy}'),
          ],
        ),
      ),
    );
  }
}